package edu.valle.modules.inventory.service.impl;
import static org.junit.jupiter.api.Assertions.assertEquals; import static org.mockito.Mockito.*;
import edu.valle.modules.catalog.entity.ProductVariant; import edu.valle.modules.inventory.dto.request.StockInRequest; import edu.valle.modules.inventory.dto.response.StockMovementResponse; import edu.valle.modules.inventory.entity.*; import edu.valle.modules.inventory.mapper.InventoryMapper; import edu.valle.modules.inventory.repository.*; import edu.valle.modules.users.entity.User; import edu.valle.modules.users.repository.UserRepository; import java.util.Optional; import org.junit.jupiter.api.*; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension;
@ExtendWith(MockitoExtension.class) class InventoryServiceImplTest {
 @Mock InventoryRepository inventories; @Mock StockMovementRepository movements; @Mock UserRepository users; @Mock InventoryMapper mapper; InventoryServiceImpl service;
 @BeforeEach void setup(){service=new InventoryServiceImpl(inventories,movements,users,mapper);}
 @Test void stockBelongsToVariant(){ProductVariant v=new ProductVariant();v.setId(7L);Inventory i=new Inventory();i.setProductVariant(v);i.setCurrentStock(5);User u=new User();u.setId(2L);StockMovement saved=new StockMovement();StockMovementResponse response=mock(StockMovementResponse.class);when(inventories.findByProductVariantId(7L)).thenReturn(Optional.of(i));when(users.findById(2L)).thenReturn(Optional.of(u));when(movements.save(any())).thenReturn(saved);when(mapper.toMovementResponse(saved)).thenReturn(response);service.addStock(7L,new StockInRequest(3,2L,"Compra"));assertEquals(8,i.getCurrentStock());verify(inventories).save(i);ArgumentCaptor<StockMovement> captor=ArgumentCaptor.forClass(StockMovement.class);verify(movements).save(captor.capture());assertEquals(v,captor.getValue().getProductVariant());}
}
